import{_ as i,o as s,c as l,a2 as t}from"./chunks/framework.BflysNKA.js";const u=JSON.parse('{"title":"审查","description":"","frontmatter":{},"headers":[],"relativePath":"api/moderation.md","filePath":"api/moderation.md","lastUpdated":1778577020000}'),e={name:"api/moderation.md"};function n(h,a,p,r,o,d){return s(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="审查" tabindex="-1">审查 <a class="header-anchor" href="#审查" aria-label="Permalink to &quot;审查&quot;">​</a></h1><p>审查接口一般用于文本安全分类或输入预检查。需要时先在模型广场查看对应模型。</p><p>这类接口更适合放在“内容进入主模型之前”或“内容发布出去之前”，而不是替代业务本身的人工判断。</p><p>很多业务第一次接审查接口时，容易直接把它理解成“自动封禁器”。<br> 更稳的理解方式是：它先给你一个风险信号，帮助你在真正进入聊天、发布、存档或自动执行之前，多一道判断。</p><h2 id="创建审查-post" tabindex="-1">创建审查 POST <a class="header-anchor" href="#创建审查-post" aria-label="Permalink to &quot;创建审查 POST&quot;">​</a></h2><p>地址：<code>POST https://xiaolan1.cn/v1/moderations</code></p><h3 id="常用请求参数" tabindex="-1">常用请求参数 <a class="header-anchor" href="#常用请求参数" aria-label="Permalink to &quot;常用请求参数&quot;">​</a></h3><ul><li><code>model</code>：审查模型</li><li><code>input</code>：待检查文本</li></ul><p>大多数情况下，先从单段文本开始测试最稳。<br> 如果后续需要批量检查，再按你的业务把长内容拆段处理。</p><p>第一次测试时，最好顺手准备两条样本：</p><ul><li>一条明显正常的文本</li><li>一条你预期更容易命中风险类别的文本</li></ul><p>这样你更容易看懂返回结构，也更容易知道这套模型当前是不是已经正常工作。</p><h3 id="示例请求" tabindex="-1">示例请求 <a class="header-anchor" href="#示例请求" aria-label="Permalink to &quot;示例请求&quot;">​</a></h3><p>先把 <code>MODEL</code> 替换成模型广场里实际可用的 Moderation 模型名：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;替换成模型广场里的 Moderation 模型名&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://xiaolan1.cn/v1/moderations</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Authorization: Bearer &lt;你的 API Key&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;{</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">model</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">$MODEL</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">input</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">需要检查的文本</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">\\&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">}&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="响应" tabindex="-1">响应 <a class="header-anchor" href="#响应" aria-label="Permalink to &quot;响应&quot;">​</a></h3><p>常见字段包括：</p><ul><li>是否命中风险</li><li>命中类别</li><li>各类别分值</li></ul><p>实际字段结构会和当前模型能力有关，但排障时通常先看“是否命中”和“命中了哪一类”就够了。</p><p>如果你的业务后面还要做阈值判断，再继续看各类别分值。<br> 第一次接通时，不建议一上来就把阈值写死，因为不同模型、不同语料下，分数分布可能会差很多。</p><h2 id="使用位置" tabindex="-1">使用位置 <a class="header-anchor" href="#使用位置" aria-label="Permalink to &quot;使用位置&quot;">​</a></h2><p>常见放在这些环节：</p><ul><li>用户输入进入聊天模型前</li><li>内容发布前</li><li>批量导入知识库前</li><li>自动化脚本执行高风险操作前</li></ul><p>如果你已经有主聊天模型，可以把审查理解成它前后的“守门环节”：</p><ul><li><strong>前置审查</strong>：先检查输入值不值得继续送进主模型</li><li><strong>后置审查</strong>：先检查输出内容是否适合继续展示、保存或转发</li></ul><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>审查结果只作为风控信号，不要替代业务判断</li><li>命中类别要结合上下文处理</li><li>批量内容先分段，再逐段检查</li><li>是否支持图片或更复杂输入，以模型广场和当前模型实际能力为准</li></ul><p>如果你准备真的把它接进生产流程，再多做一步：<br> 先拿自己业务里已经知道答案的一小批样本跑一遍，看看哪些类别容易误报、哪些阈值更适合你自己的内容环境。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="模型不可用" tabindex="-1">模型不可用 <a class="header-anchor" href="#模型不可用" aria-label="Permalink to &quot;模型不可用&quot;">​</a></h3><p>审查模型和聊天模型不是一类。回模型广场确认是否有可用的 Moderation 模型。</p><h3 id="分数怎么看" tabindex="-1">分数怎么看 <a class="header-anchor" href="#分数怎么看" aria-label="Permalink to &quot;分数怎么看&quot;">​</a></h3><p>分数越高，命中对应类别的可能性越高。不同模型的阈值不一定完全相同，生产使用前先用自己的样本校准。</p><p>也正因为阈值不是天然统一的，所以不要把别人的阈值教程原样搬过来就上线。<br> 先用你自己的文本样本试一轮，通常会比照抄一条固定数字可靠得多。</p><h3 id="为什么主聊天模型可用-但审查接口不可用" tabindex="-1">为什么主聊天模型可用，但审查接口不可用 <a class="header-anchor" href="#为什么主聊天模型可用-但审查接口不可用" aria-label="Permalink to &quot;为什么主聊天模型可用，但审查接口不可用&quot;">​</a></h3><p>审查模型和聊天模型通常不是同一种模型能力。聊天能用，不代表当前 Key 自动拥有审查模型权限。先回模型广场确认可用模型，再检查这把 Key 的分组和模型权限。</p>`,36)])])}const c=i(e,[["render",n]]);export{u as __pageData,c as default};
